//! Cross-validation: compare ALL Level 1 signing precomputed constants
//! against the reference output.
//!
//! The expected values come from `tools/c-validate/signing_precomp_expected.txt`,
//! generated by `tools/c-validate/signing_precomp_cval`.
//!
//! Every constant is compared string-for-string. Mismatches are reported
//! with full context (label, expected, got).

use num_bigint::BigInt;
use std::collections::HashMap;

use sqisign_rs::precomp::level1::{e0_basis, ec_params};
use sqisign_rs::precomp_signing::level1::{
    endomorphism_action, quaternion_constants, quaternion_data, torsion_constants,
};

fn load_expected() -> HashMap<String, String> {
    let raw = include_str!("../../../tools/c-validate/signing_precomp_expected.txt");
    let mut map = HashMap::new();
    for line in raw.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') || line.starts_with("===") {
            continue;
        }
        if let Some((key, val)) = line.split_once('=') {
            map.insert(key.to_string(), val.to_string());
        }
    }
    map
}

fn assert_match(expected: &HashMap<String, String>, key: &str, got: &str) {
    let exp = expected
        .get(key)
        .unwrap_or_else(|| panic!("Missing key in C output: {key}"));
    assert_eq!(
        got, exp,
        "\nMISMATCH for {key}:\n  Rust: {got}\n  C:    {exp}"
    );
}

fn bigint_to_decimal(b: &BigInt) -> String {
    format!("{b}")
}

fn fp_limbs_to_hex_csv(limbs: &[u64]) -> String {
    limbs
        .iter()
        .map(|l| format!("{:#x}", l))
        .collect::<Vec<_>>()
        .join(",")
}

// ========================================================================
// Tests
// ========================================================================

#[test]
fn crossvalidate_torsion_constants() {
    let expected = load_expected();

    assert_match(&expected, "TORSION_2POWER_BYTES", "32");
    assert_match(
        &expected,
        "TWO_TO_SECURITY_BITS",
        &bigint_to_decimal(&torsion_constants::TWO_TO_SECURITY_BITS),
    );
    assert_match(
        &expected,
        "TORSION_PLUS_2POWER",
        &bigint_to_decimal(&torsion_constants::TORSION_PLUS_2POWER),
    );
    assert_match(
        &expected,
        "SEC_DEGREE",
        &bigint_to_decimal(&torsion_constants::SEC_DEGREE),
    );
    assert_match(
        &expected,
        "COM_DEGREE",
        &bigint_to_decimal(&torsion_constants::COM_DEGREE),
    );
}

