#[test]
fn crossvalidate_endomorphism_curves_and_bases() {
    let expected = load_expected();

    struct CurveRefs {
        a_re: &'static [u64; 5],
        a_im: &'static [u64; 5],
        c_re: &'static [u64; 5],
        c_im: &'static [u64; 5],
        a24_x_re: &'static [u64; 5],
        a24_x_im: &'static [u64; 5],
        a24_z_re: &'static [u64; 5],
        a24_z_im: &'static [u64; 5],
        p_x_re: &'static [u64; 5],
        p_x_im: &'static [u64; 5],
        p_z_re: &'static [u64; 5],
        p_z_im: &'static [u64; 5],
        q_x_re: &'static [u64; 5],
        q_x_im: &'static [u64; 5],
        q_z_re: &'static [u64; 5],
        q_z_im: &'static [u64; 5],
        pmq_x_re: &'static [u64; 5],
        pmq_x_im: &'static [u64; 5],
        pmq_z_re: &'static [u64; 5],
        pmq_z_im: &'static [u64; 5],
    }

    macro_rules! curve_ref {
        ($idx:literal) => {
            paste::paste! {
                CurveRefs {
                    a_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A_RE>],
                    a_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A_IM>],
                    c_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_C_RE>],
                    c_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_C_IM>],
                    a24_x_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A24_X_RE>],
                    a24_x_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A24_X_IM>],
                    a24_z_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A24_Z_RE>],
                    a24_z_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _CURVE_A24_Z_IM>],
                    p_x_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_P_X_RE>],
                    p_x_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_P_X_IM>],
                    p_z_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_P_Z_RE>],
                    p_z_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_P_Z_IM>],
                    q_x_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_Q_X_RE>],
                    q_x_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_Q_X_IM>],
                    q_z_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_Q_Z_RE>],
                    q_z_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_Q_Z_IM>],
                    pmq_x_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_PMQ_X_RE>],
                    pmq_x_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_PMQ_X_IM>],
                    pmq_z_re: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_PMQ_Z_RE>],
                    pmq_z_im: &endomorphism_action::[<ENDOMORPHISM_ $idx _BASIS_PMQ_Z_IM>],
                }
            }
        };
    }

    let curves = [
        curve_ref!(0),
        curve_ref!(1),
        curve_ref!(2),
        curve_ref!(3),
        curve_ref!(4),
        curve_ref!(5),
        curve_ref!(6),
    ];

    for (idx, c) in curves.iter().enumerate() {
        let pfx = format!("ENDOMORPHISM[{idx}]");

        let checks: &[(&str, &[u64; 5])] = &[
            ("curve.A.re", c.a_re),
            ("curve.A.im", c.a_im),
            ("curve.C.re", c.c_re),
            ("curve.C.im", c.c_im),
            ("curve.A24.x.re", c.a24_x_re),
            ("curve.A24.x.im", c.a24_x_im),
            ("curve.A24.z.re", c.a24_z_re),
            ("curve.A24.z.im", c.a24_z_im),
            ("basis.P.x.re", c.p_x_re),
            ("basis.P.x.im", c.p_x_im),
            ("basis.P.z.re", c.p_z_re),
            ("basis.P.z.im", c.p_z_im),
            ("basis.Q.x.re", c.q_x_re),
            ("basis.Q.x.im", c.q_x_im),
            ("basis.Q.z.re", c.q_z_re),
            ("basis.Q.z.im", c.q_z_im),
            ("basis.PmQ.x.re", c.pmq_x_re),
            ("basis.PmQ.x.im", c.pmq_x_im),
            ("basis.PmQ.z.re", c.pmq_z_re),
            ("basis.PmQ.z.im", c.pmq_z_im),
        ];

        for (suffix, limbs) in checks {
            let key = format!("{pfx}.{suffix}");
            assert_match(&expected, &key, &fp_limbs_to_hex_csv(limbs.as_ref()));
        }
    }
}

#[test]
fn crossvalidate_endomorphism_action_matrices() {
    let expected = load_expected();

    // Rust stores row-major: [0][0], [0][1], [1][0], [1][1]
    // C prints row-major:    [0][0], [0][1], [1][0], [1][1]
    // Same order, direct index mapping.

    struct ActionRefs {
        action_i: &'static [std::sync::LazyLock<BigInt>; 4],
        action_j: &'static [std::sync::LazyLock<BigInt>; 4],
        action_k: &'static [std::sync::LazyLock<BigInt>; 4],
        action_gen2: &'static [std::sync::LazyLock<BigInt>; 4],
        action_gen3: &'static [std::sync::LazyLock<BigInt>; 4],
        action_gen4: &'static [std::sync::LazyLock<BigInt>; 4],
    }

    macro_rules! action_ref {
        ($idx:literal) => {
            paste::paste! {
                ActionRefs {
                    action_i: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_I>],
                    action_j: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_J>],
                    action_k: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_K>],
                    action_gen2: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_GEN2>],
                    action_gen3: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_GEN3>],
                    action_gen4: &endomorphism_action::[<ENDOMORPHISM_ $idx _ACTION_GEN4>],
                }
            }
        };
    }

    let actions = [
        action_ref!(0),
        action_ref!(1),
        action_ref!(2),
        action_ref!(3),
        action_ref!(4),
        action_ref!(5),
        action_ref!(6),
    ];

    for (idx, a) in actions.iter().enumerate() {
        let pfx = format!("ENDOMORPHISM[{idx}]");

        let matrices: &[(&str, &[std::sync::LazyLock<BigInt>; 4])] = &[
            ("action_i", a.action_i),
            ("action_j", a.action_j),
            ("action_k", a.action_k),
            ("action_gen2", a.action_gen2),
            ("action_gen3", a.action_gen3),
            ("action_gen4", a.action_gen4),
        ];

        for (name, mat) in matrices {
            for r in 0..2 {
                for c in 0..2 {
                    let key = format!("{pfx}.{name}[{r}][{c}]");
                    let rust_i = r * 2 + c;
                    let val = &*mat[rust_i];
                    assert_match(&expected, &key, &bigint_to_decimal(val));
                }
            }
        }
    }
}

#[test]
fn crossvalidate_e0_basis() {
    let expected = load_expected();

    assert_match(
        &expected,
        "BASIS_E0_PX.re",
        &fp_limbs_to_hex_csv(&e0_basis::BASIS_E0_P_X_RE),
    );
    assert_match(
        &expected,
        "BASIS_E0_PX.im",
        &fp_limbs_to_hex_csv(&e0_basis::BASIS_E0_P_X_IM),
    );
    assert_match(
        &expected,
        "BASIS_E0_QX.re",
        &fp_limbs_to_hex_csv(&e0_basis::BASIS_E0_Q_X_RE),
    );
    assert_match(
        &expected,
        "BASIS_E0_QX.im",
        &fp_limbs_to_hex_csv(&e0_basis::BASIS_E0_Q_X_IM),
    );
}

